const checkpoints = [];

const appointments = JSON.parse(localStorage.getItem('appointments') || '[]');
const slots = JSON.parse(localStorage.getItem('appointment_slots') || '[]');
const types = JSON.parse(localStorage.getItem('appointment_types') || '[]');
const therapists = JSON.parse(localStorage.getItem('therapists') || '[]');

// Identify individual counseling appointment types
const individualTypes = types.filter(t => t.code === 'individual_counseling' && t.is_individual);
const individualTypeIds = individualTypes.map(t => t.id);

// Baseline window: next 7 days from 2026-03-03
const windowStart = new Date('2026-03-03T00:00:00-08:00');
const windowEnd = new Date('2026-03-10T23:59:59-08:00');

function slugify(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function therapistHasAnxietySpecialty(therapist) {
  if (!therapist) return false;
  const specs = (therapist.specialties || []).map(slugify);
  return specs.includes('anxiety') || specs.includes('social_anxiety') || specs.includes('generalized_anxiety');
}

// All qualifying slots in the time window
const qualifyingSlots = slots
  .filter(slot => {
    const start = new Date(slot.start_datetime);
    if (isNaN(start.getTime())) return false;
    if (start < windowStart || start > windowEnd) return false;

    if (!individualTypeIds.includes(slot.appointment_type_id)) return false;
    if (slot.session_format !== 'in_person') return false;
    if (slot.location_zip !== '94103') return false;

    const hour = start.getHours();
    const meetsTime = slot.is_evening || hour >= 17; // evening defined as >=17:00
    if (!meetsTime) return false;

    const therapist = therapists.find(t => t.id === slot.therapist_id);
    if (!therapistHasAnxietySpecialty(therapist)) return false;

    return true;
  })
  .sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));

const earliestSlot = qualifyingSlots[0] || null;

// Confirmed appointments that use a qualifying slot
const confirmedAppointments = appointments.filter(a => a.status === 'confirmed');
const matchingAppointments = confirmedAppointments.filter(appt => {
  return qualifyingSlots.some(s => s.id === appt.appointment_slot_id);
});

// CP1 (0.5): User booked at least one confirmed appointment that meets all task criteria
checkpoints.push({ passed: matchingAppointments.length > 0, weight: 0.5 });

// CP2 (0.5): The user booked the earliest qualifying slot among all that meet the criteria
let bookedEarliest = false;
if (earliestSlot) {
  bookedEarliest = matchingAppointments.some(appt => appt.appointment_slot_id === earliestSlot.id);
}
checkpoints.push({ passed: bookedEarliest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const therapists = JSON.parse(localStorage.getItem('therapists') || '[]');
const comparisonLists = JSON.parse(localStorage.getItem('therapist_comparison_lists') || '[]');
const comparisonState = comparisonLists[0] || null;
const therapistIds = comparisonState ? (comparisonState.therapist_ids || []) : [];
const comparisonViewed = JSON.parse(localStorage.getItem('task2_comparisonViewed') || 'false');

function slugify(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

// Qualifying therapists: active, trauma specialty, sliding scale, max sliding-scale fee <= 80
const qualifyingTherapists = therapists.filter(t => {
  if (t.is_active === false) return false;
  if (!t.sliding_scale_available) return false;
  if (t.sliding_scale_max_fee == null) return false;
  if (t.sliding_scale_max_fee > 80) return false;

  const specs = (t.specialties || []).map(slugify);
  return specs.includes('trauma_ptsd');
});

// Sort by lowest sliding-scale minimum fee (cheapest first)
const sortedQualifying = qualifyingTherapists.slice().sort((a, b) => {
  const aFee = a.sliding_scale_min_fee != null ? a.sliding_scale_min_fee : a.standard_session_fee || Number.MAX_SAFE_INTEGER;
  const bFee = b.sliding_scale_min_fee != null ? b.sliding_scale_min_fee : b.standard_session_fee || Number.MAX_SAFE_INTEGER;
  return aFee - bFee;
});

const targetTherapists = sortedQualifying.slice(0, 2);

const hasBothCheapest = targetTherapists.length === 2 && targetTherapists.every(t => therapistIds.includes(t.id));

// CP1 (0.6): Comparison list contains the two cheapest qualifying trauma sliding-scale therapists
checkpoints.push({ passed: hasBothCheapest, weight: 0.6 });

// CP2 (0.4): User viewed the comparison page while those two cheapest qualifying therapists were selected
const viewedWithCorrect = !!comparisonViewed && hasBothCheapest;
checkpoints.push({ passed: viewedWithCorrect, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('insurance_plans') || '[]');
const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');

// Active plans with copay <= 30
const eligiblePlans = plans.filter(p => p.is_active !== false && typeof p.copay_amount === 'number' && p.copay_amount <= 30);

let cheapestPlan = null;
if (eligiblePlans.length > 0) {
  cheapestPlan = eligiblePlans.slice().sort((a, b) => a.copay_amount - b.copay_amount)[0];
}

let matchingMessage = null;
if (cheapestPlan) {
  matchingMessage = messages.find(m =>
    m.reason === 'insurance_billing' &&
    m.insurance_plan_id === cheapestPlan.id &&
    typeof m.referenced_copay_amount === 'number' &&
    m.referenced_copay_amount === cheapestPlan.copay_amount
  ) || null;
}

// CP1 (0.7): Submitted an insurance/billing message linked to the cheapest eligible plan with the correct referenced copay amount
checkpoints.push({ passed: !!matchingMessage, weight: 0.7 });

// CP2 (0.3): Message text mentions the plan name and the copay amount
let mentionsDetails = false;
if (matchingMessage && matchingMessage.message && cheapestPlan) {
  const msgLower = String(matchingMessage.message).toLowerCase();
  const planNameLower = String(cheapestPlan.name || '').toLowerCase();
  const copayStr = String(cheapestPlan.copay_amount);
  const copayDollarStr = '$' + copayStr;

  const mentionsPlan = planNameLower.length > 0 && msgLower.includes(planNameLower);
  const mentionsCopay = msgLower.includes(copayStr) || msgLower.includes(copayDollarStr) || msgLower.includes('copay');

  mentionsDetails = mentionsPlan && mentionsCopay;
}
checkpoints.push({ passed: mentionsDetails, weight: 0.3 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('group_programs') || '[]');
const sessions = JSON.parse(localStorage.getItem('group_sessions') || '[]');
const registrations = JSON.parse(localStorage.getItem('group_registrations') || '[]');

// Baseline: tests run with system time 2026-03-03T09:00-08:00
const baseline = new Date('2026-03-03T09:00:00-08:00');
const baselineYear = 2026;
const baselineMonthIndex = 2; // March (0-based)
const nextMonthIndex = (baselineMonthIndex + 1) % 12; // April
const nextMonthYear = baselineMonthIndex === 11 ? baselineYear + 1 : baselineYear;

function findProgram(id) {
  return programs.find(g => g.id === id) || null;
}

function findSession(id) {
  return sessions.find(s => s.id === id) || null;
}

function isWeekday(weekday) {
  return ['monday', 'tuesday', 'wednesday', 'thursday', 'friday'].includes(weekday);
}

function withinTimeWindow(startTime, endTime) {
  // Strings in 'HH:MM' format; lexicographic compare is safe
  return startTime >= '18:00' && endTime <= '20:00';
}

// Registrations created after baseline
const newRegs = registrations.filter(r => {
  const created = new Date(r.created_at);
  return !isNaN(created.getTime()) && created >= baseline;
});

// Registrations for social_anxiety group programs starting next calendar month
const regsForSocialNextMonth = newRegs.filter(r => {
  const program = findProgram(r.group_program_id);
  if (!program || program.topic !== 'social_anxiety') return false;
  const start = new Date(program.start_date);
  if (isNaN(start.getTime())) return false;
  return start.getFullYear() === nextMonthYear && start.getMonth() === nextMonthIndex;
});

// From these, require weekday 6–8 pm session, 1 participant, pay_later
const fullyMatchingRegs = regsForSocialNextMonth.filter(r => {
  const session = findSession(r.group_session_id);
  if (!session) return false;
  if (!isWeekday(session.weekday)) return false;
  if (!withinTimeWindow(session.start_time, session.end_time)) return false;
  if (r.payment_option !== 'pay_later') return false;
  if (r.num_participants !== 1) return false;
  return true;
});

// CP1 (0.5): Registered (after baseline) for a social-anxiety group starting next calendar month
checkpoints.push({ passed: regsForSocialNextMonth.length > 0, weight: 0.5 });

// CP2 (0.5): That registration uses a weekday 6–8 pm session, one participant, and pay-later payment option
checkpoints.push({ passed: fullyMatchingRegs.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const appointments = JSON.parse(localStorage.getItem('appointments') || '[]');
const slots = JSON.parse(localStorage.getItem('appointment_slots') || '[]');
const types = JSON.parse(localStorage.getItem('appointment_types') || '[]');
const therapists = JSON.parse(localStorage.getItem('therapists') || '[]');

// Identify free 15-minute consult appointment types
const consultTypes = types.filter(t => t.code === 'free_consult_15' && t.is_individual && t.is_free);
const consultTypeIds = consultTypes.map(t => t.id);

// Baseline: tests run with system time 2026-03-03T09:00-08:00
const baseline = new Date('2026-03-03T09:00:00-08:00');

// New draft appointments created after baseline
const newDrafts = appointments.filter(a => {
  if (a.status !== 'draft') return false;
  const created = new Date(a.created_at);
  return !isNaN(created.getTime()) && created >= baseline;
});

function therapistQualifies(t) {
  return !!t && t.offers_online && t.has_weekend_availability && t.offers_free_consult && t.free_consult_duration_minutes === 15;
}

// Drafts that correspond to a weekend online free 15-min consult with a qualifying therapist
const qualifyingDrafts = newDrafts.filter(a => {
  if (!consultTypeIds.includes(a.appointment_type_id)) return false;
  const slot = slots.find(s => s.id === a.appointment_slot_id);
  if (!slot) return false;
  const therapist = therapists.find(t => t.id === a.therapist_id);
  if (!therapistQualifies(therapist)) return false;
  if (slot.session_format !== 'online') return false;
  if (!slot.is_weekend) return false;
  if (!slot.is_free_consult) return false;
  return true;
});

// CP1 (0.6): User created a draft appointment for a qualifying weekend online free 15-minute consult
checkpoints.push({ passed: qualifyingDrafts.length > 0, weight: 0.6 });

// Determine the earliest available weekend consult slot across all qualifying therapists
let earliestGlobalSlot = null;
if (consultTypeIds.length > 0) {
  const allConsultSlots = slots
    .filter(slot => {
      if (!consultTypeIds.includes(slot.appointment_type_id)) return false;
      if (!slot.is_weekend || !slot.is_free_consult) return false;
      if (slot.session_format !== 'online') return false;
      const therapist = therapists.find(t => t.id === slot.therapist_id);
      return therapistQualifies(therapist);
    })
    .sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));

  earliestGlobalSlot = allConsultSlots[0] || null;
}

let bookedEarliest = false;
if (earliestGlobalSlot) {
  bookedEarliest = qualifyingDrafts.some(a => a.appointment_slot_id === earliestGlobalSlot.id);
}

// CP2 (0.4): The draft appointment uses the earliest available weekend consult slot among all qualifying therapists
checkpoints.push({ passed: bookedEarliest, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

// Qualifying subscriptions: active, monthly frequency, includes parenting_families topic
const qualifyingSubs = subs.filter(s => {
  if (!s.is_active) return false;
  if (s.frequency !== 'monthly') return false;
  const topics = s.topics || [];
  return topics.includes('parenting_families');
});

// CP1 (1.0): At least one active monthly subscription that includes the Parenting & Families topic
checkpoints.push({ passed: qualifyingSubs.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const assessments = JSON.parse(localStorage.getItem('assessments') || '[]');
const questions = JSON.parse(localStorage.getItem('assessment_questions') || '[]');
const optionsAll = JSON.parse(localStorage.getItem('assessment_options') || '[]');
const sessions = JSON.parse(localStorage.getItem('assessment_sessions') || '[]');
const responsesAll = JSON.parse(localStorage.getItem('assessment_responses') || '[]');
const results = JSON.parse(localStorage.getItem('assessment_results') || '[]');
const readingLists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingListViewed = JSON.parse(localStorage.getItem('task7_readingListViewed') || 'false');

// Identify depression assessment (PHQ-9)
const depressionAssessment = assessments.find(a => a.code === 'phq_9' || a.id === 'phq9') || null;
const depressionAssessmentId = depressionAssessment ? depressionAssessment.id : 'phq9';

// Completed sessions for PHQ-9, use the most recently completed
const completedSessions = sessions
  .filter(s => s.assessment_id === depressionAssessmentId && s.is_completed)
  .sort((a, b) => new Date(a.completed_at || 0) - new Date(b.completed_at || 0));

const targetSession = completedSessions[completedSessions.length - 1] || null;

// All PHQ-9 questions
const phqQuestions = questions.filter(q => q.assessment_id === depressionAssessmentId);

// Check that for each question, the numeric_value is a middle option (1 or 2) in the 0–3 scale
let usedMiddleOptionsForAll = false;
if (targetSession && phqQuestions.length > 0) {
  const sessionResponses = responsesAll.filter(r => r.assessment_session_id === targetSession.id);
  usedMiddleOptionsForAll = phqQuestions.every(q => {
    const r = sessionResponses.find(resp => resp.assessment_question_id === q.id);
    if (!r || typeof r.numeric_value !== 'number') return false;
    return r.numeric_value === 1 || r.numeric_value === 2; // middle values on 0–3 scale
  });
}

// CP1 (0.4): Completed a PHQ-9 session with a middle response (value 1 or 2) for every question
checkpoints.push({ passed: !!targetSession && usedMiddleOptionsForAll, weight: 0.4 });

// Determine first two recommended article IDs for this assessment result
let associatedResult = null;
let firstTwoRecommended = [];
if (targetSession) {
  associatedResult = results.find(res => res.assessment_session_id === targetSession.id) || null;
  if (associatedResult && Array.isArray(associatedResult.recommended_article_ids)) {
    firstTwoRecommended = associatedResult.recommended_article_ids.slice(0, 2);
  }
}

// Get saved reading list
const readingList = readingLists[0] || null;
const savedArticleIds = readingList ? (readingList.article_ids || []) : [];

let savedBothFirstTwo = false;
if (firstTwoRecommended.length === 2) {
  savedBothFirstTwo = firstTwoRecommended.every(id => savedArticleIds.includes(id));
}

// CP2 (0.4): Saved the first two recommended articles from the PHQ-9 result to the reading list
checkpoints.push({ passed: savedBothFirstTwo, weight: 0.4 });

// CP3 (0.2): Viewed the reading list after saving those recommended articles
const viewedWithSaved = !!readingListViewed && savedBothFirstTwo;
checkpoints.push({ passed: viewedWithSaved, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const safetyPlans = JSON.parse(localStorage.getItem('safety_plans') || '[]');
const hotlines = JSON.parse(localStorage.getItem('crisis_hotlines') || '[]');

const plan = safetyPlans[0] || null;

// Match crisis_contacts to local hotlines (by phone number or name/label)
let matchedLocalHotlines = [];
if (plan && Array.isArray(plan.crisis_contacts)) {
  plan.crisis_contacts.forEach(contact => {
    if (!contact) return;
    const contactPhone = String(contact.phone || contact.phone_number || '').trim();
    const contactLabel = String(contact.label || contact.name || '').trim().toLowerCase();

    const hotline = hotlines.find(h => {
      if (!h.is_local) return false;
      const phoneMatches = contactPhone && h.phone_number === contactPhone;
      const nameMatches = contactLabel && String(h.name || '').toLowerCase() === contactLabel;
      return phoneMatches || nameMatches;
    });

    if (hotline && !matchedLocalHotlines.some(h => h.id === hotline.id)) {
      matchedLocalHotlines.push(hotline);
    }
  });
}

// CP1 (0.6): Safety plan includes at least two distinct contacts that correspond to local crisis hotlines
checkpoints.push({ passed: matchedLocalHotlines.length >= 2, weight: 0.6 });

// CP2 (0.2): Safety plan has at least one non-empty warning sign entry
let hasWarningSigns = false;
if (plan && Array.isArray(plan.warning_signs)) {
  hasWarningSigns = plan.warning_signs.some(ws => typeof ws === 'string' && ws.trim().length > 0);
}
checkpoints.push({ passed: hasWarningSigns, weight: 0.2 });

// CP3 (0.2): Safety plan has at least one non-empty coping strategy entry
let hasCopingStrategies = false;
if (plan && Array.isArray(plan.coping_strategies)) {
  hasCopingStrategies = plan.coping_strategies.some(cs => typeof cs === 'string' && cs.trim().length > 0);
}
checkpoints.push({ passed: hasCopingStrategies, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
